#include <stdio.h>

int lower_bound(int *a, int n, int x) {
    int low = 0, high = n;
    while (low < high) {
        int mid = low + (high - low) / 2;
        if (a[mid] < x) low = mid + 1;
        else high = mid;
    }
    return low;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, x;
        scanf("%d %d", &n, &x);
        int nums[100000];
        for (int i = 0; i < n; ++i) scanf("%d", &nums[i]);
        printf("%d\n", lower_bound(nums, n, x));
    }
    return 0;
}

