import sys

def lower_bound(arr, x):
    low, high = 0, len(arr)
    while low < high:
        mid = (low + high) // 2
        if arr[mid] < x:
            low = mid + 1
        else:
            high = mid
    return low

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it))
        x = int(next(it))
        nums = [int(next(it)) for _ in range(n)]
        out.append(str(lower_bound(nums, x)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

